import{c as t,Q as r,j as s,m as a}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"SkillsBench: Benchmarking How Well Agent Skills Work Across Diverse Tasks","description":"","frontmatter":{"title":"SkillsBench: Benchmarking How Well Agent Skills Work Across Diverse Tasks","authors":"Samuel Schmidgall, Michael Moor, Hamed Nilforoshan, Jure Leskovec","published":"2026-02-13T00:00:00.000Z","source":"https://arxiv.org/abs/2602.12670"},"headers":[],"relativePath":"research/agent-harness/references/2026-02-13-skills-bench-agent-skills-2602-12670.md","filePath":"research/agent-harness/references/2026-02-13-skills-bench-agent-skills-2602-12670.md","lastUpdated":1779901665000}'),i={name:"research/agent-harness/references/2026-02-13-skills-bench-agent-skills-2602-12670.md"};function n(l,e,o,d,c,h){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="skillsbench-benchmarking-how-well-agent-skills-work-across-diverse-tasks" tabindex="-1">SkillsBench: Benchmarking How Well Agent Skills Work Across Diverse Tasks <a class="header-anchor" href="#skillsbench-benchmarking-how-well-agent-skills-work-across-diverse-tasks" aria-label="Permalink to &quot;SkillsBench: Benchmarking How Well Agent Skills Work Across Diverse Tasks&quot;">​</a></h1><p><strong>Authors</strong>: Samuel Schmidgall, Michael Moor, Hamed Nilforoshan, Jure Leskovec <strong>Published</strong>: February 13, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">https://arxiv.org/abs/2602.12670</a><strong>arXiv ID</strong>: 2602.12670 <strong>Categories</strong>: cs.AI, cs.LG</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>SkillsBench is the first benchmark specifically designed to evaluate how well agent <strong>Skills</strong> (structured packages of procedural knowledge) improve performance across diverse tasks. Across 84 tasks in 11 domains, curated skills increase performance by +16.2 percentage points while self-generated skills decrease performance by −1.3pp. Optimal skill count is 2–3; beyond that, performance degrades from context overload. Healthcare tasks benefit most (+51.9pp); software engineering benefits least (+4.5pp).</p><hr><h2 id="benchmark-design" tabindex="-1">Benchmark Design <a class="header-anchor" href="#benchmark-design" aria-label="Permalink to &quot;Benchmark Design&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Total tasks</td><td>84</td></tr><tr><td>Domains</td><td>11</td></tr><tr><td>Skill types evaluated</td><td>No skills, curated skills, self-generated skills</td></tr><tr><td>Models tested</td><td>Claude Sonnet 4.5, GPT-5, Gemini 3.1 Pro (primary)</td></tr></tbody></table><h3 id="domains-covered" tabindex="-1">Domains Covered <a class="header-anchor" href="#domains-covered" aria-label="Permalink to &quot;Domains Covered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Domain</th><th>Task Examples</th></tr></thead><tbody><tr><td>Healthcare</td><td>Medical diagnosis, treatment planning</td></tr><tr><td>Software Engineering</td><td>Code generation, debugging</td></tr><tr><td>Legal</td><td>Contract review, case analysis</td></tr><tr><td>Finance</td><td>Investment analysis, risk assessment</td></tr><tr><td>Education</td><td>Curriculum design, problem explanation</td></tr><tr><td>Scientific Research</td><td>Hypothesis generation, literature synthesis</td></tr><tr><td>Data Analysis</td><td>Statistical analysis, visualization</td></tr><tr><td>Creative Writing</td><td>Story generation, editing</td></tr><tr><td>Customer Service</td><td>Query resolution, escalation</td></tr><tr><td>Logistics</td><td>Route optimization, supply chain</td></tr><tr><td>Cybersecurity</td><td>Threat analysis, incident response</td></tr></tbody></table><hr><h2 id="key-results" tabindex="-1">Key Results <a class="header-anchor" href="#key-results" aria-label="Permalink to &quot;Key Results&quot;">​</a></h2><h3 id="skills-vs-no-skills" tabindex="-1">Skills vs. No Skills <a class="header-anchor" href="#skills-vs-no-skills" aria-label="Permalink to &quot;Skills vs. No Skills&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Performance Delta</th></tr></thead><tbody><tr><td><strong>Curated skills</strong></td><td><strong>+16.2 pp</strong></td></tr><tr><td>No skills (baseline)</td><td>0 pp</td></tr><tr><td>Self-generated skills</td><td><strong>−1.3 pp</strong></td></tr></tbody></table><p><strong>Critical finding</strong>: Self-generated skills (where the agent writes its own skill documentation) underperform baseline. Only externally curated skills reliably improve performance.</p><h3 id="performance-by-domain" tabindex="-1">Performance by Domain <a class="header-anchor" href="#performance-by-domain" aria-label="Permalink to &quot;Performance by Domain&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Domain</th><th>Curated Skill Gain</th></tr></thead><tbody><tr><td><strong>Healthcare</strong></td><td><strong>+51.9 pp</strong></td></tr><tr><td>Legal</td><td>+38.7 pp</td></tr><tr><td>Scientific Research</td><td>+29.4 pp</td></tr><tr><td>Finance</td><td>+22.1 pp</td></tr><tr><td>Education</td><td>+18.6 pp</td></tr><tr><td>Data Analysis</td><td>+15.3 pp</td></tr><tr><td>Customer Service</td><td>+12.8 pp</td></tr><tr><td>Creative Writing</td><td>+9.2 pp</td></tr><tr><td>Logistics</td><td>+7.6 pp</td></tr><tr><td>Cybersecurity</td><td>+6.1 pp</td></tr><tr><td><strong>Software Engineering</strong></td><td><strong>+4.5 pp</strong></td></tr></tbody></table><h3 id="why-healthcare-gains-most-swe-gains-least" tabindex="-1">Why Healthcare Gains Most, SWE Gains Least <a class="header-anchor" href="#why-healthcare-gains-most-swe-gains-least" aria-label="Permalink to &quot;Why Healthcare Gains Most, SWE Gains Least&quot;">​</a></h3><p><strong>Healthcare</strong>: Domain knowledge is highly specialized and not uniformly present in model pretraining. Skills provide critical procedural knowledge (clinical guidelines, diagnostic frameworks) that models lack or underweight.</p><p><strong>Software Engineering</strong>: Models are extensively pretrained on code — SWE knowledge is already densely represented in weights. Skills add marginal procedural information on top of existing strong priors.</p><hr><h2 id="optimal-skill-count" tabindex="-1">Optimal Skill Count <a class="header-anchor" href="#optimal-skill-count" aria-label="Permalink to &quot;Optimal Skill Count&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Number of Skills</th><th>Performance (vs. Baseline)</th></tr></thead><tbody><tr><td>0</td><td>Baseline</td></tr><tr><td>1</td><td>+8.4 pp</td></tr><tr><td><strong>2</strong></td><td><strong>+15.9 pp</strong></td></tr><tr><td><strong>3</strong></td><td><strong>+16.2 pp (peak)</strong></td></tr><tr><td>4</td><td>+12.7 pp</td></tr><tr><td>5</td><td>+9.1 pp</td></tr><tr><td>6+</td><td>Degrading further</td></tr></tbody></table><p><strong>Finding</strong>: 2–3 skills is the empirical optimum. Beyond 3 skills, context overload reduces performance — the model&#39;s attention is diluted across too many procedural specifications.</p><hr><h2 id="why-self-generated-skills-fail-−1-3-pp" tabindex="-1">Why Self-Generated Skills Fail (−1.3 pp) <a class="header-anchor" href="#why-self-generated-skills-fail-−1-3-pp" aria-label="Permalink to &quot;Why Self-Generated Skills Fail (−1.3 pp)&quot;">​</a></h2><p>When agents generate their own skills from examples or task descriptions, performance drops below baseline. Root causes identified:</p><ol><li><strong>Recursive drift</strong>: Self-generated skills reflect the model&#39;s existing biases, amplifying errors rather than correcting them</li><li><strong>Circular reasoning</strong>: The model generates skills based on what it already does, not what it should do differently</li><li><strong>Overfitting to examples</strong>: Self-generated skills overfit to the specific examples used in generation, reducing generalization</li><li><strong>False confidence</strong>: Skills authored by the model create false confidence, causing the model to skip verification steps it would otherwise perform</li></ol><hr><h2 id="skill-quality-dimensions" tabindex="-1">Skill Quality Dimensions <a class="header-anchor" href="#skill-quality-dimensions" aria-label="Permalink to &quot;Skill Quality Dimensions&quot;">​</a></h2><p>The paper proposes three dimensions for evaluating skill quality:</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Description</th><th>Correlates With</th></tr></thead><tbody><tr><td><strong>Specificity</strong></td><td>Concrete procedural steps vs. vague guidance</td><td>Higher performance gains</td></tr><tr><td><strong>Groundedness</strong></td><td>Based on verified domain knowledge</td><td>Reliability</td></tr><tr><td><strong>Orthogonality</strong></td><td>Skills don&#39;t overlap significantly</td><td>Efficiency at 2-3 count</td></tr></tbody></table><p>Low-quality skills (high vagueness, ungrounded assertions, high overlap) explain the self-generated skill failure mode.</p><hr><h2 id="implications-for-skill-design" tabindex="-1">Implications for Skill Design <a class="header-anchor" href="#implications-for-skill-design" aria-label="Permalink to &quot;Implications for Skill Design&quot;">​</a></h2><ol><li><strong>Curate, don&#39;t generate</strong>: Human-authored skills with domain expert review outperform agent-generated skills by 17.5pp</li><li><strong>Domain matters</strong>: Prioritize skills for high-knowledge-barrier domains (healthcare, legal, science) over domains with dense pretraining (coding, math)</li><li><strong>Limit to 2-3 skills per session</strong>: Loading more degrades performance through context dilution</li><li><strong>Structure over prose</strong>: Skills with numbered steps, decision criteria, and explicit procedures outperform narrative-style skills</li></ol><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly validates and calibrates workspace skill design:</p><ol><li><strong>+16.2pp curated skills vs. −1.3pp self-generated</strong>: The workspace skill design (human-authored, structured, with I/O contracts) is the right approach. Avoid having agents auto-generate new skills at runtime.</li><li><strong>2-3 skills optimal</strong>: When loading context into a session via <code>@rules/</code>, load only the most relevant 2-3 skills per task. CLAUDE.md&#39;s lazy-load approach (on-demand skill triggers) correctly avoids the context overload trap.</li><li><strong>+51.9pp Healthcare, +4.5pp SWE</strong>: Most workspace skills focus on SWE (implementer, test-writer, review-hub) — the lowest-gain domain. Workspace ROI from skills would be higher in security, architecture, and research domains where knowledge is more specialized.</li><li><strong>Self-generated skill risk for autoresearch</strong>: The autoresearch loop should NOT be configured to write new skills to <code>.claude/skills/</code> without human review — recursive drift is empirically confirmed to hurt performance.</li><li><strong>Skill quality dimensions (specificity, groundedness, orthogonality)</strong>: Useful checklist for evaluating existing workspace skills and identifying which ones to refactor or remove.</li></ol>',40)])])}const k=t(i,[["render",n]]);export{p as __pageData,k as default};
